LEFT JOIN program p
  ON p.university_id = u.id
 AND lower(trim(p.name)) = lower(trim(v.name))
 AND COALESCE(p.degree, '') = COALESCE(v.degree, '')
 AND COALESCE(p.language, '') = COALESCE(v.language, '')
WHERE lower(trim(u.name)) = lower(trim('İstinye University'))
  AND p.id IS NULL;


-- Refresh programs_count from actual rows
UPDATE university u SET programs_count = sub.cnt
FROM (SELECT university_id, COUNT(*) AS cnt FROM program GROUP BY university_id) sub
WHERE u.id = sub.university_id
  AND lower(trim(u.name)) IN ('Acibadem University', 'Altınbaş University', 'Arel University', 'Aydın University', 'Beykent University', 'Bezmialem Vakıf University', 'Biruni University', 'CIU University', 'European University of Lefke', 'Final International University', 'Işık University', 'Türk Hava Kurumu University', 'İstinye University');
